1	export type Cell = [x: number, y: number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const livesNextGeneration = (isAlive: boolean, aliveNeighborCount: number): boolean =>
15	  aliveNeighborCount === 3 || (isAlive && aliveNeighborCount === 2);
16	
17	const candidateCells = (liveCells: Cell[]): Map<string, Cell> => {
18	  const byKey = new Map<string, Cell>();
19	  for (const cell of liveCells) {
20	    byKey.set(cellKey(cell), cell);
21	    for (const neighbor of neighborsOf(cell)) {
22	      const key = cellKey(neighbor);
23	      if (!byKey.has(key)) byKey.set(key, neighbor);
24	    }
25	  }
26	  return byKey;
27	};
28	
29	export function nextGeneration(cells: Cell[]): Cell[] {
30	  const aliveKeys = new Set(cells.map(cellKey));
31	  const countAliveNeighbors = (cell: Cell): number =>
32	    neighborsOf(cell).filter((n) => aliveKeys.has(cellKey(n))).length;
33	
34	  return [...candidateCells(cells)]
35	    .filter(([key, cell]) => livesNextGeneration(aliveKeys.has(key), countAliveNeighbors(cell)))
36	    .map(([, cell]) => cell);
37	}
