2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die from underpopulation — [(0,1), (1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with exactly 2 neighbors survives (blinker center) — center of vertical blinker survives", () => {
15	    // vertical blinker [(0,0),(0,1),(0,2)] — center (0,1) has 2 neighbors and survives
16	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
17	    expect(result).toContainEqual([0, 1]);
18	  });
19	  it("live cell with 3 neighbors survives — survival T-shape example", () => {
20	    // T-shape: top row + bottom-center. (1,0) has 3 live neighbors → survives.
21	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 2]]);
22	    expect(result).toContainEqual([1, 0]);
23	  });
24	  it("live cell with 4 neighbors dies from overpopulation — center of full 3x3 dies", () => {
25	    // full 3x3 grid — center (1,1) has 8 live neighbors → dies
26	    const cells: [number, number][] = [
27	      [0, 0], [1, 0], [2, 0],
28	      [0, 1], [1, 1], [2, 1],
29	      [0, 2], [1, 2], [2, 2],
