34	  it("dead cell with exactly 3 neighbors becomes alive — reproduction L-shape (1,1) becomes alive", () => {
35	    // L-shape: [(0,0),(1,0),(0,1)] — dead cell (1,1) has 3 live neighbors → born
36	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
37	    expect(result).toContainEqual([1, 1]);
38	  });
39	  it("blinker oscillates vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
40	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
